  /* ============ 공통 셀 렌더러 (재고 그리드) ============ */
  function _stockNumberCell(v, unit) {
    const n = Number(v) || 0;
    return `<strong>${n.toLocaleString()}</strong>${unit ? `<span style="color:var(--color-text-muted); font-size:var(--fs-xs); margin-left:2px;">${unit}</span>` : ''}`;
  }
  // 원자재 재고 — 매/연 듀얼 표기 (500매 = 1연 기준)
  //   "1,000매 / 2연", "200매 / 0.4연", "-60매 / -0.1연" 식
  function _maeYeonStr(n) {
    const m = Number(n) || 0;
    const y = m / 500;
    const yStr = (Number.isInteger(y) ? String(y) : y.toFixed(1));
    return `${m.toLocaleString()}매 / ${yStr}연`;
  }
  function _stockSafeCell(current, safe, unit) {
    if (!safe) return `<span style="color:var(--color-text-muted);">—</span>`;
    return `${Number(safe).toLocaleString()}${unit ? `<span style="color:var(--color-text-muted); font-size:var(--fs-xs); margin-left:2px;">${unit}</span>` : ''}`;
  }
  // 일시 컬럼 — 도메인 표준 SWADPIA §1.2 (`YY/MM/DD   HH:MM`) 은 _fmtYMDHM2 (위에 이미 정의) 를 사용

  /* ============ 자재 > 재고 > 원자재 재고 ============ */
  function initMatStockRawPage() {
    const pageEl = document.getElementById('page-mat-stock-raw');
    if (!pageEl) return;
    pageEl.__onShow = () => {
      _buildProductGridPage(pageEl, {
        store: { list() { return App.MatStock.listRaw(); } },
        gridType: 'standard',       // 표준 그리드 — 이미지 컬럼 없음 (CLAUDE.md Grid 유형 룰)
        // 등록 버튼 없음 — 재고는 입출고로만 변동 (툴바에 등록 X)
        registerLabel: null,
        // 행 클릭 비활성 — 재고 상세 팝업 제거. 누적입고/출고 셀 클릭만 활성.
        rowIdKey: 'matCode',
        search: {
          // 기간검색 제거 — 재고는 시점 스냅샷(현재고 기준)이라 기간 기준 일자 컬럼이 없음 (검색 표준 데이터 없음)
          showDateRange: false,
          cols: 4,
          conditions: [
            { value: 'all',     label: '전체' },
            { value: 'matCode', label: '자재코드' },
            { value: 'matName', label: '자재명' },
            { value: 'spec',    label: '규격' },
          ],
          advanced: [
            { name: 'major',   label: '대분류',   options: ['스탠다드','스페셜','패키지','스티커'] },
            { name: 'mid',     label: '중분류',   options: ['스노우지','모조지','켄트지','아트지','머메이드','랑데뷰','판지'] },
            { name: 'cutType', label: '재단유형', options: ['국전(4×6전)','46전(46/2)'] },
            { name: 'status',  label: '재고상태', options: ['결품','부족','주의','정상'] },
          ],
        },
        filter(rows, p) {
          const term = (p && (p.q || p.term) || '').toString().trim().toLowerCase();
          if (term) {
            const cond = (p && p.cond) || 'all';
            const fields = cond === 'all' ? ['matCode','matName','spec'] : [cond];
            rows = rows.filter(r => fields.some(k => String(r[k] || '').toLowerCase().includes(term)));
          }
          const adv = (p && p.adv) || {};
          Object.keys(adv).forEach(k => {
            if (adv[k]) rows = rows.filter(r => String(r[k] || '') === adv[k]);
          });
          return rows;
        },
        columns: [
          { key: 'no',           label: 'No',         width: '56px',  align: 'center',
            render: (r) => `<span style="color:var(--color-text-muted);">${r.no}</span>` },
          { key: 'matCode',      label: '자재코드',   width: '110px', align: 'center',
            render: (r) => `<strong style="color:var(--color-brand-primary);">${_escHTML(r.matCode)}</strong>` },
          { key: 'major',        label: '대분류',     width: '110px', align: 'center',
            render: (r) => r.major ? `<span class="pill pill--muted">${_escHTML(r.major)}</span>` : '' },
          { key: 'mid',          label: '중분류',     width: '110px', align: 'center',
            render: (r) => _escHTML(r.mid || '-') },
          { key: 'matName',      label: '자재명',     width: '220px', align: 'left',
            render: (r) => `<span class="pgrid__name">${_escHTML(r.matName)}</span>` },
          { key: 'spec',         label: '규격',       width: '120px', align: 'center',
            render: (r) => _escHTML(r.spec || '-') },
          { key: 'cumulativeIn', label: '누적입고수량', width: '170px', align: 'right',
            render: (r) => {
              const n = Number(r.cumulativeIn) || 0;
              if (n <= 0) return '<span style="color:var(--color-text-muted);">0매 / 0연</span>';
              const y = n / 500; const yStr = Number.isInteger(y) ? String(y) : y.toFixed(1);
              return `<a href="javascript:;" data-matstock-inbounds="${_escHTML(r.matCode)}" style="color:var(--color-brand-primary); font-weight:var(--fw-semibold); text-decoration:underline;">${n.toLocaleString()}매</a><span style="color:var(--color-text-muted); font-size:var(--fs-xs); margin-left:6px;">/ ${yStr}연</span>`;
            } },
          { key: 'cumulativeOut',label: '누적출고수량', width: '170px', align: 'right',
            render: (r) => {
              const n = Number(r.cumulativeOut) || 0;
              if (n <= 0) return '<span style="color:var(--color-text-muted);">0매 / 0연</span>';
              const y = n / 500; const yStr = Number.isInteger(y) ? String(y) : y.toFixed(1);
              return `<a href="javascript:;" data-matstock-outbounds="${_escHTML(r.matCode)}" style="color:var(--color-brand-primary); font-weight:var(--fw-semibold); text-decoration:underline;">${n.toLocaleString()}매</a><span style="color:var(--color-text-muted); font-size:var(--fs-xs); margin-left:6px;">/ ${yStr}연</span>`;
            } },
          { key: 'prevStock',    label: '직전재고',   width: '150px', align: 'right',
            render: (r) => `<span style="color:var(--color-text-sub);">${_maeYeonStr(r.prevStock)}</span>` },
          { key: 'currentStock', label: '현재재고',   width: '150px', align: 'right',
            render: (r) => `<strong>${_maeYeonStr(r.currentStock)}</strong>` },
        ],
      });

      // 누적입고/출고 셀 클릭 → 레이어 팝업 (행 클릭 = 상세 모달과 분리)
      pageEl.addEventListener('click', (e) => {
        const inA = e.target.closest('[data-matstock-inbounds]');
        if (inA) {
          e.stopPropagation();
          e.preventDefault();
          App.openMatStockInboundsModal(inA.dataset.matstockInbounds);
          return;
        }
        const outA = e.target.closest('[data-matstock-outbounds]');
        if (outA) {
          e.stopPropagation();
          e.preventDefault();
          App.openMatStockOutboundsModal(outA.dataset.matstockOutbounds);
          return;
        }
      });
    };
  }


