        <div class="fm-tbl__row fm-tbl__row--2">
          <div class="fm-tbl__label">도착 일시</div>
          <div class="fm-tbl__value">${_fmtYMDHM2(rec.arriveAt)}</div>
          <div class="fm-tbl__label">도착 km</div>
          <div class="fm-tbl__value"><strong>${(Number(rec.arriveKm) || 0).toLocaleString()}</strong> km</div>
        </div>
