  /* ============================================================
   *  장비/부품 도메인 — 시드 날짜 시프트
   *  ----------------------------------------------------------
   *  시드 데이터의 날짜들은 앵커(2026-05-21) 기준으로 작성됨.
   *  로드 시점에 (오늘 − 앵커) 경과일만큼 모든 날짜를 평행이동해
   *  기본 기간 필터(최근 1개월)·월마감 당월 뷰에 시드가 항상 노출되게 한다.
   *  (모든 시드 오프셋이 과거 방향이므로 시프트 후에도 미래 날짜는 생기지 않음)
   * ============================================================ */
  const _EQ_SEED_ANCHOR = '2026-05-21';
  const _EQ_SHIFT_DAYS = (function () {
    const a = new Date(_EQ_SEED_ANCHOR + 'T00:00:00');
    const t = new Date(); t.setHours(0, 0, 0, 0);
    return Math.max(0, Math.round((t - a) / 86400000));
  })();
  function _eqShiftDates(v) {
    if (!_EQ_SHIFT_DAYS) return v;
    if (Array.isArray(v)) { for (let i = 0; i < v.length; i++) v[i] = _eqShiftDates(v[i]); return v; }
    if (v && typeof v === 'object') { Object.keys(v).forEach(k => { v[k] = _eqShiftDates(v[k]); }); return v; }
    if (typeof v === 'string') {
      const m = v.match(/^(\d{4})-(\d{2})-(\d{2})([ T].*)?$/);   // YYYY-MM-DD(+시각) 만 시프트 — YYYY-MM(도입년월) 등은 유지
      if (m) {
        const d = new Date(`${m[1]}-${m[2]}-${m[3]}T00:00:00`);
        if (!isNaN(d.getTime())) {
          d.setDate(d.getDate() + _EQ_SHIFT_DAYS);
          const p = (n) => String(n).padStart(2, '0');
          return `${d.getFullYear()}-${p(d.getMonth() + 1)}-${p(d.getDate())}${m[4] || ''}`;
        }
      }
    }
    return v;
  }

