    if (host) return { backdrop: host, panel: document.getElementById(prefix + '-modal') };
    // auto: 대형(.modal--xl) — 최대 1800px 까지 확장 (변동이력 다컬럼 테이블 수용)
    const sizeCls = opts.auto ? 'modal--xl' : 'modal--lg';
    const sizeStyle = opts.auto ? 'max-width:1800px; width:95%;' : 'max-width:920px; width:96%;';
    const wrap = document.createElement('div');
    wrap.innerHTML = `
      <div class="modal-backdrop" data-${prefix}-host>
        <div class="modal ${sizeCls}" id="${prefix}-modal" role="dialog" aria-hidden="true" style="${sizeStyle} max-height:92vh; display:flex; flex-direction:column;">
          <header class="modal__header" style="flex:0 0 auto;">
            <div class="modal__title" data-${prefix}-title>${title}</div>
            <button class="modal__close" type="button" data-${prefix}-close aria-label="닫기">✕</button>
          </header>
          <div class="modal__body" data-${prefix}-body style="padding:18px 22px; flex:1 1 auto; overflow:auto; min-height:0;"></div>
          <footer class="modal__footer" data-${prefix}-foot style="justify-content:space-between; flex:0 0 auto;"></footer>
        </div>
      </div>`;
